"""
MKT Context Commentary — Genesis chapters 41–42
Run: python3 scripts/zc-context-genesis-41-42.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (existing entries)

Key decisions in this range:
- Ch41: Egyptological background is central — Nile, sacred cows (Hathor), magicians
  (hartummim), vizier investiture ceremony, Heliopolis/On sun cult, Egyptian name-giving.
- "Abreck" (v43) rendered "Make way!" — the Hebrew term is unique; likely an Egyptian
  loanword meaning "bow down" or a cry to clear the path.
- Zaphenath-Paneah: Egyptian etymology debated; following von Rad/Kitchen that it is
  authentic Egyptian — not treated as symbolic Hebrew.
- Asenath's father Potiphera as priest of On (Heliopolis) signals the highest Egyptian
  priestly class; not allegorized away.
- Ch42: Honor-shame dynamics dominate; the brothers' return of silver creates acute
  social anxiety in a patron-client economy. The spy accusation is read in ANE
  border-control context, not just narrative tension.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-context commentary for Genesis 41–42. Ch41 covers Joseph's rise through
#   Pharaoh's court — Egyptological background is essential throughout. Ch42 opens the
#   brother-reunion sequence — dominated by honor-shame, conscience, and the dream-
#   fulfillment motif.
# CHANGE? If data/commentary/mkt-context/genesis.json schema changes, update
#   load_comm/save_comm helpers in Z_COMMENTARY_SCRIPT_GUIDE.md accordingly.
# VERIFY: After running, python3 -c "import json; d=json.load(open('data/commentary/mkt-context/genesis.json')); print(len(d.get('41',{})), len(d.get('42',{})))" should print "57 38".

NEW_DATA = {
"41": {
"1": "<p>&#8220;Two full years&#8221; (Heb. <em>šĕnātayim yāmîm</em>, lit. &#8220;two years of days&#8221;) marks precise elapsed time from the cupbearer&#8217;s restoration (40:20&#8211;23). The phrase emphasizes duration: the God who gives dreams does not forget his plans even when human agents forget their obligations. Joseph has been in Egyptian custody approximately eleven years at this point (sold at 17, stands before Pharaoh at 30, v46). The narrator anchors the story in Pharaoh&#8217;s throne-room and the Nile, immediately invoking Egypt&#8217;s foundational geography.</p>",
"2": "<p>The Nile (<em>yĕʾōr</em>, an Egyptian loanword for the Nile specifically, not a generic river) was Egypt&#8217;s axis mundi — the source of all fertility, controlled by the annual inundation. Fat cows grazing in the reeds (<em>āḥû</em>, a borrowed Egyptian word for Nile-grass) are an image of ideal Nilotic abundance. Cows were sacred animals in Egyptian religion: Hathor, the goddess of joy, love, and abundance, was represented as a cow or cow-horned woman, and the cow-headed Isis nursed Horus. Pharaoh&#8217;s court would instantly recognize the symbolic resonance of bovine imagery in a dream from the Nile.</p>",
"3": "<p>The contrasting seven gaunt cows stand on the &#8220;riverbank&#8221; (<em>śĕpaṯ hayyĕʾōr</em>) alongside the fat ones before consuming them. The image of Nile-born famine cows standing alongside abundance cows creates an impossible visual — in the real world gaunt cows cannot consume fat ones. This impossibility signals that the dream is not natural but revelatory: ordinary rules of cause and effect are suspended to communicate divine information. Egyptian dream-interpretation texts (the Chester Beatty Dream Book, c. 1280 BCE) categorized such impossible inversions as high-significance omens.</p>",
"4": "<p>The gaunt cows consuming the fat ones without growing fat themselves (cf. v21) is the key interpretive detail Pharaoh will stress in his retelling. In Egyptian dream interpretation, the consuming of one thing by another typically signified the defeat or absorption of the consumed thing. That the consuming cows remain unchanged signals that the destruction of plenty leaves no residue — the famine is not just reduction but annihilation of surplus. Egypt&#8217;s economy was entirely dependent on Nile flood levels; a sequence of low floods (&#8220;lean years&#8221;) could devastate the agrarian system within a single generation.</p>",
"5": "<p>The second dream shifts to agriculture — grain (<em>qāneh</em>, &#8220;stalk&#8221; or &#8220;reed&#8221;) rather than cattle. Seven full heads on a single stalk is unrealistic agronomically (most wheat varieties produce 1&#8211;3 heads per stalk), again marking the dream as non-natural. Egyptian agriculture was primarily wheat and barley grown in the Nile-flood plain; grain abundance was measured by stalk-weight and head-fullness. The doubling of the dream in two different domains (pastoral/agricultural) intensifies the message and will be interpreted by Joseph as God&#8217;s confirmation (v32).</p>",
"6": "<p>The east wind (<em>qādîm</em>) is the hot, desiccating desert wind (the <em>khamsin</em>) that blows from the Sinai and Arabian deserts in spring, scorching crops and stripping moisture from vegetation. In Egyptian agricultural life the east wind was associated with crop failure; a grain-dream featuring east-wind-scorched heads would have been immediately alarming to any Egyptian familiar with the agricultural calendar. The thin, scorched heads parallel the gaunt cows — the same disaster told in a different register.</p>",
"7": "<p>Pharaoh&#8217;s waking after the second dream with the recognition &#8220;it had been a dream&#8221; (<em>wĕhinnēh ḥălōm</em>, lit. &#8220;and behold, a dream&#8221;) implies a moment of disorientation between dream-reality and waking — the vividness of the dreams made them feel real on waking. In Egyptian royal ideology, Pharaoh was uniquely positioned to receive divine messages through dreams as an intermediary between the gods and the human world; a disturbing dream to Pharaoh was a disturbing message to the state.</p>",
"8": "<p>The <em>ḥarṭummîm</em> (magicians/scribes) are the Egyptian priestly class specializing in sacred texts, dream interpretation, and omen reading — the same word used in Exod 7:11 for the court magicians who oppose Moses. The term is an Egyptian loanword (<em>hry-tp</em>, &#8220;chief of the stelae&#8221; or &#8220;ritual expert&#8221;). The &#8220;wise men&#8221; (<em>ḥăkāmîm</em>) were court advisers with general administrative and intellectual expertise. That neither group could interpret the dreams despite Egypt&#8217;s extensive dream-manual tradition sets up Joseph&#8217;s God-given interpretation as categorically superior to human learning.</p>",
"9": "<p>The chief cupbearer&#8217;s confession — &#8220;Today I am reminded of my shortcomings&#8221; (<em>ḥăṭāʾay ʾănî mazkîr hayyôm</em>) — is significant. <em>Ḥāṭāʾ</em> can mean &#8220;sin,&#8221; &#8220;shortcoming,&#8221; or &#8220;failure&#8221;; he is confessing that he failed in his duty by forgetting Joseph (40:23). The urgency of Pharaoh&#8217;s distress overcomes whatever embarrassment led him to suppress the memory. In an Egyptian court, failing to mention a resource to Pharaoh when it becomes relevant would be a serious lapse of duty; his confession functions as much as self-protective CYA as moral reflection.</p>",
"10": "<p>The cupbearer&#8217;s brief account of the imprisonment episode is carefully constructed for Pharaoh&#8217;s ears: he mentions Pharaoh&#8217;s anger, the imprisonment under Potiphar&#8217;s oversight, and the shared experience — establishing the context without self-incrimination. The reference to &#8220;the house of the captain of the guard&#8221; (<em>bayt śar haṭṭabbāḥîm</em>) confirms the setting of ch40 and implicitly identifies Joseph&#8217;s employer (Potiphar). The narration within the narration creates a layered testimony structure that ANE court records frequently employed.</p>",
"11": "<p>&#8220;Each dream had a meaning of its own&#8221; (<em>kĕpitrōnô ḥālamdnû</em>, lit. &#8220;according to its interpretation we dreamed&#8221;) echoes Joseph&#8217;s earlier assertion (40:8) that interpretations belong to God. The cupbearer&#8217;s framing acknowledges that their dreams were individually meaningful — not random — which validates the interpretive process and sets up the comparison with Pharaoh&#8217;s situation.</p>",
"12": "<p>&#8220;A young Hebrew&#8221; (<em>naʿar ʿibrî</em>) — the double identification is socially marked. <em>Naʿar</em> (youth/servant) signals low social status; &#8220;Hebrew&#8221; signals foreign origin. In the Egyptian social hierarchy, a young foreign slave in the captain of the guard&#8217;s household would rank near the bottom of court society. The cupbearer presents Joseph as an unexpected source of wisdom — the very marginality he emphasizes makes the accuracy of the interpretation more striking. The phrase also positions Joseph within his social coordinates for Pharaoh&#8217;s benefit.</p>",
"13": "<p>&#8220;Things turned out exactly as he interpreted them&#8221; — the verification of Joseph&#8217;s prior accuracy is the cupbearer&#8217;s strongest argument for his relevance now. In ANE divination culture, an interpreter whose predictions proved accurate acquired recognized authority. The outcome — restoration for the cupbearer, death (impalement, <em>tālāh</em>, probably exposed on a stake as in Egyptian execution practice) for the baker — functions as Joseph&#8217;s documented track record.</p>",
"14": "<p>Joseph is &#8220;quickly brought from the dungeon&#8221; — the urgency reflects Pharaoh&#8217;s distress. Before appearing before Pharaoh, Joseph shaved and changed clothes. Shaving is a distinctively Egyptian grooming practice; Egyptian men were generally clean-shaven (especially court officials and priests), while Semitic peoples typically wore beards. Joseph&#8217;s shaving signals cultural adaptation to Egyptian court protocol — he is not presented to Pharaoh as a disheveled Hebrew prisoner but as someone who understands the decorum of the court. The change of clothes removes the visible markers of imprisonment.</p>",
"15": "<p>Pharaoh&#8217;s direct address — &#8220;I have heard it said of you that when you hear a dream you can interpret it&#8221; — is notable for its accuracy and its limitation. What Pharaoh knows is secondhand hearsay through the cupbearer; he frames it as reported speech (&#8220;it is said of you&#8221;) rather than direct claim. This invites Joseph to confirm or deny, setting up his theologically important response. Pharaoh&#8217;s acknowledgment that no one in his court could interpret positions the Egyptian wisdom establishment as having failed before the question reaches Joseph.</p>",
"16": "<p>&#8220;I cannot do it&#8212;but God will give Pharaoh the answer he desires.&#8221; Joseph&#8217;s deflection is a studied contrast with Egyptian diviners who claimed technical expertise. He denies personal interpretive ability while asserting divine agency. The word <em>ʾĕlōhîm</em> (God) — Joseph&#8217;s consistent term for YHWH in this narrative — appears in Pharaoh&#8217;s polytheistic court without explanation. Joseph does not translate it into Egyptian theological terminology; he introduces his God&#8217;s communication to Pharaoh as an empirical fact rather than a competing theological claim.</p>",
"17": "<p>Pharaoh&#8217;s retelling of the dream (vv17&#8211;24) is not verbatim repetition of vv1&#8211;7 — it adds the detail in v19 (&#8220;I had never seen such ugly cows in all the land of Egypt&#8221;) and emphasizes the completeness of his distress in v24 (&#8220;none of them could explain it to me&#8221;). In ANE narrative, repetition with variation signals that the repetition is not filler but carries new information. Pharaoh stands &#8220;on the bank of the Nile&#8221; rather than &#8220;by the Nile&#8221; — the royal figure at the Nile&#8217;s edge invokes the pharaonic imagery of the king as mediator of the inundation.</p>",
"18": "<p>The Nile appeared twice as the source of both sets of cows. In Egyptian cosmology, the Nile was associated with Hapy, god of the annual flood, whose abundance sustained Egypt. Pharaoh&#8217;s dream drawing from the Nile rather than from the sky or desert signals that this revelation concerns Egypt&#8217;s fundamental agricultural system, not foreign invasion or political upheaval. The reeds (<em>āḥû</em>) where the fat cows graze are the lush Nile-margin vegetation that feeds livestock during flood season — an image of maximum Egyptian prosperity.</p>",
"19": "<p>Pharaoh&#8217;s emphasis that the gaunt cows were the worst he had ever seen in Egypt signals that this is not normal agricultural variation but extreme catastrophe. His personal claim of never having seen such poor cattle implies decades of Pharaonic observation — this is outside his experience entirely. ANE royal inscriptions frequently invoke the king&#8217;s long experience as an authority for their pronouncements; Pharaoh&#8217;s &#8220;never seen in all Egypt&#8221; frames the coming famine as historically unprecedented.</p>",
"20": "<p>The dream-detail that the lean cows &#8220;ate up&#8221; the fat cows is repeated; in Pharaoh&#8217;s retelling it is equally impossible and equally central. The eating without transformation (v21) is the interpretive crux. Elsewhere in ANE omen literature, dreams of consumption signify military defeat (the consumed = the defeated), but here the transformation-failure signal is unique — the famine will consume abundance without producing new prosperity from the consumption.</p>",
"21": "<p>&#8220;No one could tell that they had done so; they looked just as ugly as before.&#8221; This is the detail that most troubled Pharaoh and that is not in the original narrative (vv3&#8211;4 imply but do not state it). In Joseph&#8217;s interpretation, this will signify that the years of famine will be so severe that the memory of the years of plenty will be erased (v31). The motif of abundance being &#8220;forgotten&#8221; — not just depleted but unremembered — is the distinctive horror of the famine: it will not merely follow the plenty but will negate it retroactively in human memory.</p>",
"22": "<p>The grain-dream is retold with its own emphasis. &#8220;Full and good&#8221; (<em>bĕrîʾōt wĕṭōbôt</em>) uses the same adjectives as the fat cows (v2); the two dreams are linguistically linked as one. A single stalk bearing seven good heads is an image of supernatural productivity — not seven stalks but one, suggesting unified and concentrated abundance controlled by a single source. The motif will be reflected in Joseph&#8217;s proposed solution: centralized storage under a single authority (vv33&#8211;36).</p>",
"23": "<p>&#8220;Withered and thin and scorched by the east wind&#8221; — Pharaoh&#8217;s retelling of the deteriorated grain adds detail (&#8220;withered,&#8221; <em>daqqôt</em>, &#8220;shrunken/thin&#8221;) absent from the narrator&#8217;s original account (v6). The east wind (<em>rûaḥ qādîm</em>) was the agricultural nightmare of the Nile Valley; it arrives dry and hot and can destroy grain in days. The three descriptors (withered, thin, scorched) accumulate to paint maximum ruin — this is not drought alone but compound environmental catastrophe.</p>",
"24": "<p>Pharaoh&#8217;s frustration is explicit: he went to the magicians and none could explain it. The repetition of the magicians&#8217; failure (cf. v8) from Pharaoh&#8217;s own mouth serves as a second witness to the inadequacy of Egyptian wisdom before divine revelation. It also explains why Pharaoh is so open to Joseph: the interpretive guild has already been exhausted. This sets up a recurring motif in Exodus where Pharaoh&#8217;s magicians can initially replicate Moses&#8217; signs but ultimately cannot match divine power (Exod 7&#8211;8).</p>",
"25": "<p>&#8220;The dreams of Pharaoh are one and the same.&#8221; Joseph&#8217;s opening assertion is a hermeneutical key: two seemingly different dreams (cattle/grain) have a single meaning because God gave both. This interpretive move — reading two distinct visions as one unified divine communication — would have been recognizable in ANE dream interpretation practice, where sequence-dreams were sometimes combined. But Joseph grounds the unity not in technical method but in God&#8217;s single purposeful revelation: &#8220;God has revealed to Pharaoh what he is about to do.&#8221;</p>",
"26": "<p>The identification of seven fat cows = seven good years of grain is a standard ANE symbolic equivalence in omen literature: the dreamed image represents something in the natural or political world. Egyptian and Mesopotamian dream manuals used systematic correspondences (cow = year; head of grain = harvest yield). What distinguishes Joseph&#8217;s interpretation is not the formal method but the theological ground: the source is Israel&#8217;s God revealing future history, not a technical deduction from a manual.</p>",
"27": "<p>Seven lean cows = seven years of famine. The east wind scorching grain was a recurring historical reality in the Levant-Egypt agricultural zone: the Admonitions of Ipuwer (Egyptian wisdom text, possibly Middle Kingdom, c. 1850 BCE) describes social collapse during grain failure in terms strikingly similar to Joseph&#8217;s description — storehouses empty, people eating grass, the social order inverted. Whether or not this text refers to the same events, it shows that multi-year famine was within Egyptian historical memory as a catastrophe of the first order.</p>",
"28": "<p>Joseph&#8217;s repetition of &#8220;God has shown Pharaoh what he is about to do&#8221; (repeating v25b) is emphatic and serves multiple functions: it reinforces the divine source, it places Pharaoh in the position of recipient (not initiator) of this knowledge, and it implicitly positions Joseph as the interpreter-messenger between God and Egypt&#8217;s king. The phrase &#8220;what he is about to do&#8221; (<em>ʾăšer hāʾĕlōhîm ʿōśeh</em>) uses the active participle — what God is in the process of doing — not a remote future but an imminent divine action already in motion.</p>",
"29": "<p>&#8220;Seven years of great abundance&#8221; (<em>śēbaʿ šĕnê śābāʿ</em>) — the wordplay is untranslatable: <em>šeba</em> (seven) and <em>śābāʿ</em> (abundance/satiation) share three consonants. The coming abundance is divinely excessive, not merely adequate. Egypt&#8217;s Nile-flood agriculture operated on predictable rhythms; above-average inundation in successive years would produce bumper crops that filled granaries. The pattern of 7+7 years may reflect a 14-year climate cycle, but the narrative presents it as God&#8217;s deliberate sequencing rather than natural variation.</p>",
"30": "<p>&#8220;All the abundance&#8230; will be forgotten&#8221; — the economic reality Joseph describes is the collapse of buffer stocks through multi-year famine. Egypt historically maintained state granaries to buffer against low-flood years; a sufficiently long famine would exhaust those reserves and then begin consuming seed grain, creating a spiral where the capacity to recover is itself destroyed. The word &#8220;ravage&#8221; (<em>wĕkillāh</em>, from <em>kālāh</em> = to consume/destroy completely) signals not depletion but annihilation.</p>",
"31": "<p>The severity of the coming famine is described in terms of amnesia rather than merely scarcity: the abundance will not be &#8220;remembered&#8221; (<em>lōʾ yizzāḵēr</em>) in the land. In a pre-modern subsistence economy, the psychological impact of sustained hunger was complete — cognitive function, social cooperation, and cultural activity all degraded under severe caloric deprivation. Joseph is describing not just economic collapse but the erasure of social memory. The seven lean years will define reality so completely that the seven abundant years will seem like a fantasy.</p>",
"32": "<p>&#8220;The reason the dream was given in two forms is that the matter has been firmly decided by God.&#8221; The doubling of the dream is interpreted as divine confirmation (<em>nākôn haddābār</em>, &#8220;the word is established/firm&#8221;). In ANE legal procedure, two witnesses established a matter as fact (cf. Deut 17:6; 19:15). God&#8217;s dual witness — two dreams from different domains (pastoral and agricultural) — signals that this is irrevocable divine decree, not a conditional warning. The phrase &#8220;God will do it soon&#8221; (<em>mĕmahēr hāʾĕlōhîm laʿăśōtô</em>) uses the Piel of <em>māhar</em> (to hasten) — this is already in motion.</p>",
"33": "<p>Joseph pivots immediately from interpretation to policy proposal — an unusual move for an interpreter in a royal court, where advice unsolicited by the king could be dangerous presumption. His proposal is pragmatically urgent: if the interpretation is true and God&#8217;s action is imminent (v32), delay in preparation is catastrophic. The call for &#8220;a discerning and wise man&#8221; (<em>nābôn wĕḥākām</em>) uses the standard Wisdom vocabulary for administrative competence; Joseph is proposing a solution that falls within Egyptian administrative tradition — centralized management — not an alien imposition.</p>",
"34": "<p>&#8220;A fifth of the harvest&#8221; (<em>ḥāmiš</em>) — a 20% tax on agricultural surplus during the seven abundant years. This rate is significant: Egyptian agricultural taxation typically ran between 10&#8211;33% depending on land type and flood yield. Joseph&#8217;s proposed rate is moderate and politically viable. The &#8220;commissioners&#8221; (<em>pĕqudîm</em>) would be tax officials analogous to those already in Egypt&#8217;s complex administrative system, which included nome (district) administrators, scribes, and grain assessors documented in Middle Kingdom papyri.</p>",
"35": "<p>&#8220;Store up the grain under the authority of Pharaoh&#8221; — Joseph&#8217;s grain-storage plan is entirely consistent with what Egyptologists know of Egyptian state granaries. The Middle Kingdom (c. 2055&#8211;1650 BCE) saw extensive expansion of state grain storage as part of centralized redistribution. Grain was stored in large mudbrick silos attached to temples and palaces; the Beni Hasan tomb paintings depict grain-measuring and storage operations. Joseph&#8217;s proposal is not novel — it is the systematic expansion of an existing Egyptian institution.</p>",
"36": "<p>&#8220;So that the country may not be ruined by the famine&#8221; — the goal is national preservation (<em>wĕlōʾ-tiqqāreṯ hāʾāreṣ</em>, lit. &#8220;so that the land not be cut off&#8221;). <em>Kārat</em> (to cut off) is the covenant penalty for covenant violation, but here used for national destruction. Egypt&#8217;s collapse under famine would not just mean hungry people — it would mean the dissolution of the state, the collapse of temple cult, the end of the organized social order that constituted Egyptian civilization. Joseph is proposing the salvation of Egypt as a polity.</p>",
"37": "<p>&#8220;The plan seemed good to Pharaoh and to all his officials.&#8221; Pharaoh&#8217;s decision-making model is explicitly collegial here: the officials (Heb. <em>ʿăbādāyw</em>, &#8220;servants/courtiers&#8221;) participate in evaluating the proposal. Egyptian administrative decision-making in the Middle and New Kingdoms involved privy councils of senior officials who advised Pharaoh; major policy decisions were not purely autocratic. The unanimous approval of Joseph&#8217;s plan by the entire court removes any political obstacle to his appointment.</p>",
"38": "<p>&#8220;Can we find anyone like this man, one in whom is the spirit of God?&#8221; Pharaoh&#8217;s rhetorical question identifies the quality that distinguishes Joseph from the court&#8217;s magicians: <em>rûaḥ ʾĕlōhîm</em> (spirit of God). In Egyptian theology, divine spirit or power (<em>ka</em>) was associated with royal and priestly charisma; Pharaoh himself was considered a divine being. By attributing Joseph&#8217;s wisdom to a divine spirit, Pharaoh is not confessing Israel&#8217;s God — he is fitting Joseph into his own theological category. The irony is that his polytheistic acknowledgment of &#8220;the spirit of God&#8221; is, in the narrative, accurate monotheistic testimony.</p>",
"39": "<p>Pharaoh&#8217;s formal commission — &#8220;Since God has made all this known to you, there is no one so discerning and wise as you&#8221; — is a throne-room declaration that publicly establishes Joseph&#8217;s authority. In Egyptian court protocol, a royal declaration before the assembled court had legal force; what Pharaoh declares before witnesses becomes royal decree. The attributes &#8220;discerning and wise&#8221; (<em>nābôn wĕḥākām</em>) precisely echo Joseph&#8217;s own recommendation in v33 — Pharaoh has recognized Joseph as exactly the person his own plan required.</p>",
"40": "<p>&#8220;You shall be in charge of my palace&#8221; — the title implied corresponds to the Egyptian <em>imy-r pr</em> (overseer of the house), the vizier&#8217;s role as highest non-royal official. The vizier controlled Egypt&#8217;s administration, judiciary, and treasury. &#8220;All my people are to submit to your orders&#8221; reflects the vizier&#8217;s judicial authority over the population. The exception &#8220;only with respect to the throne will I be greater than you&#8221; mirrors precisely the constitutional limitation on Egypt&#8217;s historical viziers as documented in the Duties of the Vizier papyrus (New Kingdom, though likely reflecting earlier practice).</p>",
"41": "<p>The formal investiture — &#8220;I hereby put you in charge of the whole land of Egypt&#8221; — is the climactic throne-room declaration. Egyptian vizierial appointments are documented in the Duties of the Vizier text and in tomb paintings showing the investiture ceremony. The appointment of a foreigner to the vizierate is exceptional but not unique; the Second Intermediate Period saw multiple non-Egyptians in high administrative roles, and the Hyksos period (c. 1650&#8211;1550 BCE) saw Semitic rulers governing Egypt. Whether Joseph&#8217;s appointment should be located in the Hyksos period or the Middle Kingdom is debated, but the narrative reflects authentic Egyptian administrative practice.</p>",
"42": "<p>Three investiture symbols: signet ring (<em>ṭabbaʿaṯ</em>) — Pharaoh&#8217;s ring transferred the authority to seal documents in Pharaoh&#8217;s name, the highest administrative delegated power; fine linen robes (<em>bigdê-šēš</em>, Egyptian <em>šs</em> = a fine royal linen, the same used for priestly garments) — marking elite Egyptian status; gold chain (<em>rĕbid hazzāhāb</em>) — Egyptian gold collars were the standard marker of royal favor, documented in tomb paintings of investiture scenes (e.g. the tomb of Khnumhotep at Beni Hasan). These three symbols are archaeologically and textually consistent with Egyptian court practice.</p>",
"43": "<p>Riding in the second chariot with the crowd shouting <em>ʾabrēk</em> before him — this word (<em>ʾabrēk</em>, hapax legomenon in the Hebrew Bible) is disputed: possibly Egyptian <em>ib-r-k</em> (&#8220;bow the knee&#8221;) or an Akkadian loanword meaning &#8220;attention!&#8221; The procession of the vizier through the city with people clearing the way is consistent with Egyptian ceremonial practice. Tomb reliefs depict officials in chariot processions with crowds prostrating; the cry before the chariot is a standard feature of royal and viceregal processions documented in Egyptian texts.</p>",
"44": "<p>&#8220;Without your word no one will lift hand or foot in all Egypt&#8221; is the formal declaration of Joseph&#8217;s executive authority. The idiom &#8220;lift hand or foot&#8221; (<em>yārîm ʾîš ʾeṯ-yādô wĕʾeṯ-raglô</em>) is a merism for any executive or judicial action — no one acts without Joseph&#8217;s authorization. The Duties of the Vizier text specifies that the vizier controlled reporting from every government department; no significant action in the country proceeded without his knowledge and approval. Joseph&#8217;s role is not honorary but functionally supreme beneath Pharaoh.</p>",
"45": "<p>Pharaoh gives Joseph an Egyptian name and an Egyptian wife. <em>Zaphenath-Paneah</em> — various etymologies have been proposed: Kitchen suggests Egyptian <em>Dd-pa-ntr-iw.f-ʿnḫ</em> (&#8220;Joseph who is called God speaks and he lives&#8221;); von Rad suggests it is authentic Egyptian though the exact form is uncertain. Asenath (<em>ʾĀsĕnaṯ</em>, Egyptian <em>Ns-nt</em> or <em>ʾIt-neit</em>) is a documented Egyptian name. Her father Potiphera (<em>Pōṭîpherāʿ</em>) is priest of <em>ʾŌn</em> — Heliopolis, the great sun-temple city 10 km north of Memphis, center of Egyptian solar theology and cult of Ra. Marrying Joseph into the Heliopolitan priestly family fully integrates him into the Egyptian elite class — his children will be legally Egyptian.</p>",
"46": "<p>&#8220;Joseph was thirty years old when he entered the service of Pharaoh&#8221; — the specific age functions as a biographical marker connecting Joseph to the wider biblical age-of-ministry pattern: David became king at 30 (2 Sam 5:4), the Levites entered full temple service at 30 (Num 4:3), and Jesus began his public ministry at &#8220;about thirty years old&#8221; (Luke 3:23). The thirteen years between Joseph&#8217;s sale (age 17, 37:2) and his elevation (age 30) are compressed in the narrative but were years of servitude, false accusation, and imprisonment — his formation in the school of suffering.</p>",
"47": "<p>The seven years of abundance fulfilled Joseph&#8217;s interpretation exactly. The &#8220;plentiful production&#8221; (<em>waṯaʿaś hāʾāreṣ liqmāṣîm</em>, lit. &#8220;the land made fistfuls&#8221; — an unusual word suggesting abundance by the handful) reflects exceptionally high Nile floods that deposit unusually thick silt and enable multiple harvests. The Palermo Stone (an Egyptian royal annals document) records Nile inundation heights for early dynasties; above-average floods are correlated with high grain yields in Egyptian administrative records.</p>",
"48": "<p>Joseph&#8217;s administrative strategy — storing grain city by city in each city&#8217;s own surrounding fields — reflects sound logistical practice: grain is heavy and transport expensive in a pre-mechanized economy. Storing regionally avoids the cost of transporting grain across long distances during the abundant years, and positions distribution points where population density is highest. This decentralized storage within a centralized system mirrors the administrative structure of Middle Kingdom Egypt, where nome (district) granaries operated under central scribal oversight.</p>",
"49": "<p>&#8220;Like the sand of the sea&#8212;it was so much that he stopped keeping records.&#8221; The sand-of-the-sea hyperbole is an ANE idiom for uncountable quantity (cf. Gen 22:17; 32:12); its use here signals that Joseph&#8217;s accumulation exceeded the administrative capacity to measure it. Egyptian scribal records tracked grain to the heqat (a dry measure); that Joseph abandoned record-keeping signals quantities that overwhelmed the existing accounting system. The hyperbole also prepares the audience for the magnitude of the subsequent distribution (vv55&#8211;57).</p>",
"50": "<p>Two sons born before the famine years — their birth during the years of plenty is narratively significant: they arrive while Joseph is flourishing, and their names will interpret his experience of loss and recovery. That they are born to Asenath, daughter of a Heliopolitan priest, makes them legally Egyptian of the priestly class on their mother&#8217;s side. The tension between their Egyptian legal status and their place in the Abrahamic covenant line will be resolved explicitly in Gen 48, when Jacob adopts them into his twelve-tribe structure.</p>",
"51": "<p><em>Mĕnaššeh</em> (Manasseh) is linked to <em>naššānî</em> (&#8220;has made me forget&#8221;) from the root <em>nāšāh</em>. Joseph&#8217;s naming theology: God has caused him to &#8220;forget all my trouble and all my father&#8217;s household.&#8221; This is not amnesia but the healing resolution of painful memory through new life — the wound is not unreal but no longer defining. &#8220;My father&#8217;s household&#8221; (<em>bêṯ ʾābî</em>) appears in the name-giving formula: Joseph has not forgotten his family in fact, but the ache of separation has been transformed by God&#8217;s provision into bearable memory.</p>",
"52": "<p><em>ʾEprayim</em> (Ephraim) is linked to <em>hipĕrānî</em> (&#8220;has made me fruitful&#8221;) from <em>pārāh</em>. &#8220;In the land of my suffering&#8221; (<em>bĕʾereṣ ʿonĕyî</em>) — Joseph names the land of his exile as the place where God has been fruitful, without denying that it was suffering. The pairing of Manasseh (forgetting trouble) and Ephraim (fruitfulness in suffering) creates a theology of providential suffering: the same land that was the site of affliction becomes the site of supernatural productivity. This naming theology anticipates the Joseph story&#8217;s ultimate theological claim (50:20: &#8220;You intended to harm me, but God intended it for good&#8221;).</p>",
"53": "<p>The transition from plenty to famine is marked with economical precision: &#8220;The seven years of abundance in Egypt came to an end.&#8221; The narrative does not dwell on the transition — it simply happens as Joseph predicted. The absence of drama in the shift signals the reliability of the divine word: what God announced through Joseph&#8217;s interpretation occurred without deviation. Egypt&#8217;s agricultural year was tracked by Nile flood levels; a sequence of low floods beginning the eighth year would immediately register as the prophesied shift.</p>",
"54": "<p>&#8220;There was famine in all the other lands, but in the whole land of Egypt there was food.&#8221; The famine&#8217;s scope — &#8220;all the other lands&#8221; (<em>bĕkōl hāʾărāṣôt</em>) — is presented as geographically comprehensive. The Levant, Canaan, Mesopotamia, and Arabia all show evidence of climate disruption and famine periods in the Middle Bronze Age; the narrative frames this as a regional climate event of which Egypt, uniquely, has foreknowledge and preparation because of divine revelation through Joseph. Egypt&#8217;s position as the one land with stored grain makes it the food hub for the ancient Near East.</p>",
"55": "<p>&#8220;When all Egypt began to feel the famine&#8221; — even with years of stored grain, the famine eventually affects Egypt&#8217;s own domestic food security, triggering popular appeal to Pharaoh. Pharaoh&#8217;s response — &#8220;Go to Joseph and do what he tells you&#8221; — is both a practical referral and a public confirmation of Joseph&#8217;s authority. In Egyptian administrative practice, Pharaoh&#8217;s direct endorsement of Joseph&#8217;s word to the entire population effectively makes Joseph&#8217;s authority equivalent to royal command for the duration of the crisis.</p>",
"56": "<p>&#8220;Joseph opened all the storehouses&#8221; (<em>wayyipĕtaḥ yôsēp ʾeṯ-kol-ʾăšer bāhem</em>) — the verb <em>pātaḥ</em> (open) contrasts with the closing/sealing of the stored grain during the abundant years. The opening is the activation of the entire preparatory system. Joseph &#8220;sold grain to the Egyptians&#8221; — it is a commercial transaction, not free distribution; this preserves both the state&#8217;s economic resources and the recipients&#8217; dignity (in ANE honor-shame culture, charity could be shaming; purchase preserves the appearance of self-sufficiency).</p>",
"57": "<p>&#8220;All the world came to Egypt to buy grain from Joseph, because the famine was severe everywhere.&#8221; The scope — &#8220;all the world&#8221; (<em>kol-hāʾāreṣ</em>) — is the same phrase used in 41:54 (&#8220;all the other lands&#8221;). Egypt becomes the world&#8217;s granary. This sets up the brothers&#8217; arrival in ch42 as not remarkable from an Egyptian perspective — Canaan, like all surrounding nations, was buying grain in Egypt. The family of Jacob is absorbed into this larger international famine context before the narrative narrows its focus to the brothers at Joseph&#8217;s grain counter.</p>"
},
"42": {
"1": "<p>Jacob&#8217;s question — &#8220;Why do you just keep looking at each other?&#8221; (<em>lāmmāh titrāʾû</em>, lit. &#8220;why do you look at one another?&#8221;) — captures the paralysis of a family without a plan. The Hebrew root <em>rāʾāh</em> in the Hithpael can mean &#8220;to look at each other&#8221; with the implication of helpless mutual regard. Jacob&#8217;s irritation with his sons&#8217; inaction is a father&#8217;s practicality confronting the emotional stasis of grief, guilt, and indecision. The brothers have lost Joseph — the one who would have had initiative — and their paralysis may reflect both practical uncertainty and unspoken guilt.</p>",
"2": "<p>&#8220;Go down there and buy some for us, so that we may live and not die.&#8221; The urgency — life-or-death food scarcity — explains Jacob&#8217;s willingness to send his sons to Egypt despite the risks. The phrase &#8220;we may live and not die&#8221; (<em>wĕniḥyeh wĕlōʾ nāmûṯ</em>) is blunt; no euphemism. The family of the covenant patriarch is not immune to the regional famine. Canaan had no Nile and no equivalent grain reserves; Canaanite agriculture was entirely rain-dependent and would have been devastated by the same climate event that caused Egypt&#8217;s famine (though Egypt was more prepared).</p>",
"3": "<p>&#8220;Ten of Joseph&#8217;s brothers went down to buy grain from Egypt.&#8221; The specification &#8220;ten&#8221; matters: Benjamin is excluded (v4), and the absent Joseph makes eleven total. The brothers travel as a commercial party; going to Egypt to buy grain during famine was standard practice for Canaanite and Levantine populations — multiple Egyptian texts describe &#8220;Asiatics&#8221; (Semitic peoples) coming to the Delta frontier for food during lean years (e.g. Anastasi VI papyrus describes Shasu Bedouin entering Egypt with their flocks). Ten adult men traveling together would be a significant commercial delegation.</p>",
"4": "<p>Jacob&#8217;s refusal to send Benjamin reflects the transfer of protective anxiety from Joseph to Benjamin. Benjamin is now Rachel&#8217;s only surviving son (Rachel died in 35:19); Jacob&#8217;s attachment to Benjamin replicates the favoritism that destroyed the family system (37:3&#8211;4). &#8220;He was afraid that harm might come to him&#8221; — the vague &#8220;harm&#8221; (<em>ʾāsôn</em>) is the same word Jacob will use when he fears losing Benjamin in 42:38 and 44:29; it likely means fatal accident or violence. Jacob&#8217;s overprotection of Benjamin will create the crisis of the next chapters.</p>",
"5": "<p>&#8220;Israel&#8217;s sons were among those who went to buy grain, for the famine was in the land of Canaan also.&#8221; The narrator uses &#8220;Israel&#8217;s sons&#8221; rather than &#8220;Jacob&#8217;s sons&#8221; — the covenant name is invoked as the brothers join the international traffic of famine-victims flowing toward Egypt. They are not special emissaries but part of a larger movement of peoples. This anonymity is both historically accurate (many Semitic groups traveled to Egypt for grain) and narratively significant: the covenant family is reduced to the same desperate need as any other nation.</p>",
"6": "<p>&#8220;Joseph was the governor of the land&#8212;when Joseph&#8217;s brothers arrived, they bowed down to him with their faces to the ground.&#8221; The fulfillment of Joseph&#8217;s first dream (37:7 — sheaves bowing) is stated matter-of-factly without narrative exclamation. The brothers bow (<em>wayyišṭaḥăwû</em>, Hishtaphel of <em>šāḥāh</em> = to prostrate, the same verb used in the dream&#8217;s interpretation) before the grain-official without knowing who he is. The irony is complete and deliberate: the brothers who mocked &#8220;that dreamer&#8221; enact his dream while trying to survive. The narrative fulfillment of divine revelation through ordinary economic necessity.</p>",
"7": "<p>Joseph &#8220;pretended to be a stranger and spoke harshly to them.&#8221; His disguise is not personal concealment but official distance: he addresses them as the Egyptian governor addressing foreign grain-buyers, not as a brother. The harsh speech (<em>wayyĕdabbēr ʾittām qāšôṯ</em>) was appropriate official demeanor toward foreigners in Egyptian administrative interactions; it was not unusual for Egyptian officials to interrogate foreign buyers. Joseph&#8217;s &#8220;Where do you come from?&#8221; is a standard border-control question — Egypt had formal procedures for regulating entry of foreigners.</p>",
"8": "<p>Joseph recognized the brothers but they did not recognize him. The asymmetry is plausible: Joseph was 17 when sold (37:2) and is now 39 (thirty in v46, seven abundant years = 37, onset of famine); the brothers last saw a 17-year-old Hebrew in a pit. Now they face a middle-aged Egyptian official in court regalia. The brothers would have seen thousands of foreigners in Egypt&#8217;s famine-era grain markets; there is no reason they would scrutinize each official&#8217;s face for a dead brother. Joseph, however, was expecting family members from Canaan as buyers.</p>",
"9": "<p>&#8220;Then he remembered his dreams about them.&#8221; The moment of recognition triggers memory of the prophetic dreams — Joseph now sees that this is the fulfillment he had been promised. His accusation &#8220;You are spies!&#8221; (<em>mĕragĕlîm ʾattem</em>) begins a process of testing rather than immediate revelation. In ANE border-control practice, accusations of espionage against foreign delegations were a recognized legal mechanism for detaining and interrogating them. Egypt&#8217;s eastern border was a zone of genuine security concern; the narrative&#8217;s spy-charge is not fantastic but draws on real Egyptian border-security anxiety.</p>",
"10": "<p>The brothers&#8217; defense — &#8220;Your servants have come to buy food&#8221; — uses the standard honorific self-designation <em>ʿăbāḏêkā</em> (your servants), appropriate when addressing a high Egyptian official. Their commercial purpose is offered as evidence against espionage: spies do not announce themselves as buyers. The title &#8220;my lord&#8221; (<em>ʾădōnî</em>) is the respectful address for a superior in an ANE honor-shame system; the brothers navigate the interaction entirely within the protocols of lower-status foreign petitioners before an Egyptian official of rank.</p>",
"11": "<p>&#8220;We are all the sons of one man. Your servants are honest men, not spies.&#8221; The claim of shared paternity is offered as a vouching system: family solidarity was a recognized ANE social credential. A man who had brothers — especially many brothers — was embedded in a kinship network that provided accountability; lone individuals with no family were more credible as spies. The brothers present their family structure as evidence of their legitimacy. The claim is both tactically sound and loaded with irony: the &#8220;one man&#8221; they invoke as their warranty is Jacob, whose love Joseph remembers.</p>",
"12": "<p>Joseph&#8217;s repeated insistence &#8220;No! You have come to see where our land is undefended&#8221; (<em>ʿerwat hāʾāreṣ</em>, lit. &#8220;the nakedness of the land&#8221;) — &#8220;nakedness&#8221; as a military vulnerability idiom is attested in ANE military texts. Egypt&#8217;s eastern Delta, the border with Canaan, was a strategic weak point historically penetrated by the Hyksos (c. 1650 BCE); the accusation is not geographically random. Joseph&#8217;s persistent accusation despite their denial is the method of interrogation — forcing more disclosure to build a picture of their actual family situation.</p>",
"13": "<p>The brothers&#8217; disclosure of their family structure under pressure reveals what Joseph most needed to know: Benjamin is alive (&#8220;the youngest is now with our father&#8221;) and the lost brother is &#8220;no more&#8221; (<em>ʾênennû</em>) — they assume Joseph dead. The irony is acute: they speak of Joseph&#8217;s death to Joseph himself. Their description of the family — twelve sons, one dead, one remaining with the father — is the first news Joseph has had of his family in approximately twenty years. The narrative shows him restraining an overwhelming response.</p>",
"14": "<p>Joseph&#8217;s insistence on the spy charge — &#8220;It is just as I told you: You are spies!&#8221; — is investigative strategy, not genuine belief. He needs a pretext to compel the brothers to bring Benjamin to Egypt so the second dream can be fulfilled (the eleven stars bowing, 37:9) and so he can verify the family&#8217;s state. An Egyptian official who announced he was releasing prisoners on their own word alone would be vulnerable to criticism; the institutional framework of the spy-charge gives him legal authority to hold one brother and demand the return of the others with proof of their family claims.</p>",
"15": "<p>&#8220;As surely as Pharaoh lives&#8212;&#8221; (<em>ḥê parʿōh</em>) — the oath formula using Pharaoh&#8217;s life is the highest Egyptian secular oath; it functions as Joseph claims his Egyptian official identity fully. Joseph does not swear by God (as the brothers might expect a Hebrew to) but by Pharaoh — performing his Egyptian role completely. The test he sets — bring the youngest brother — is precisely the requirement that will force a reckoning with the family&#8217;s past. The demand creates the structural necessity for the brothers to choose how to treat another favored son.</p>",
"16": "<p>Joseph&#8217;s initial demand — one brother fetches Benjamin while the rest remain imprisoned — is strategically the most leverage he can exert. It reverses the brothers&#8217; original situation: one went free (the Ishmaelites took Joseph away) while his brothers continued; now the inverse is proposed. The offer of continued grain for their households while one stays shows Joseph&#8217;s concern for the family&#8217;s survival even while he tests their honesty. The use of &#8220;prison&#8221; (<em>bêṯ hammiśmār</em>, &#8220;house of the guard/custody&#8221;) echoes the place Joseph himself had been held (40:3).</p>",
"17": "<p>Three days in custody. In ANE procedural contexts, three days is a recognized period for deliberation, assessment, or formal waiting (cf. Jonah&#8217;s three days; the three-day journey in Exod 3:18; the third day as a resolution point in multiple biblical narrative sequences). The three-day detention gives the brothers time to talk among themselves — and gives the reader and Joseph time to observe how they will respond to pressure. Their conversation in vv21&#8211;22 shows that the guilt has been long suppressed but not extinguished.</p>",
"18": "<p>&#8220;Do this and you will live, for I fear God.&#8221; Joseph&#8217;s revision of his terms — releasing nine brothers rather than one — is presented as motivated by <em>ʾĕlōhîm</em>-fear. This is a startling declaration: an Egyptian official announces that his administrative leniency is grounded in fear of God. Whether the brothers understand who the &#8220;God&#8221; is remains ambiguous — they might interpret it as Egyptian theological language. For the audience, however, it is a transparent window into Joseph&#8217;s unchanged character: even in the highest Egyptian office, his behavior is governed by the same God who was with him in prison (39:21).</p>",
"19": "<p>The revised terms — one brother imprisoned while nine take grain to Canaan and return with Benjamin — is more humane and more practical for the family. It ensures the family does not starve while Benjamin is brought; it also keeps one brother (Simeon, v24) as a hostage ensuring return. Joseph&#8217;s concern that the family&#8217;s &#8220;starving households&#8221; (<em>battêkem</em>, &#8220;your houses&#8221;) be fed reflects his care for the family he has not seen in twenty years&#8212;a care he cannot yet express directly.</p>",
"20": "<p>&#8220;So that your words may be verified and that you may not die.&#8221; The test is framed as a life-or-death verification; the brothers accept the terms and &#8220;proceeded to do&#8221; as instructed. This is the first moment of the brothers&#8217; compliance with a demand they cannot control — they have no choice. The narrative is quietly reversing the power dynamic: the brothers who had absolute power over Joseph in the pit now have no power before the Egyptian official who controls their food supply and their imprisoned sibling.</p>",
"21": "<p>The brothers&#8217; conversation — &#8220;Surely we are being punished because of our brother&#8221; — is the first moral reckoning in the story. The word &#8220;punished&#8221; (<em>ʾăšēmîm ʾănaḥnû</em>, lit. &#8220;we are guilty&#8221;) uses <em>ʾāšam</em>, the guilt-offering root — the same concept that undergirds the OT sacrificial system&#8217;s resolution of guilt. The conscience that was suppressed for twenty years surfaces under pressure. Their memory of Joseph&#8217;s distress — &#8220;we saw how distressed he was when he pleaded with us&#8221; — implies that the original scene of v24 (ch37 has no explicit pleading recorded) was more emotionally charged than the narrator chose to present.</p>",
"22": "<p>Reuben&#8217;s interjection — &#8220;Didn&#8217;t I tell you not to sin against the boy?&#8221; — is technically accurate (he proposed the cistern to avoid murder, 37:21&#8211;22) but morally insufficient: he was absent when the sale occurred (37:29) and did not prevent it. His claim now is self-exculpating: &#8220;Now we must give an accounting for his blood.&#8221; The blood-reckoning frame (<em>wĕdāmô hinnēh niḏrāš</em>, &#8220;his blood — behold it is required&#8221;) invokes Gen 9:5&#8211;6 (blood-guilt requires accounting); Reuben interprets their current suffering as retributive divine justice — an accurate theological assessment even if his own hands are not entirely clean.</p>",
"23": "<p>&#8220;They did not realize that Joseph could understand them, since he was using an interpreter.&#8221; This detail is crucial: Joseph hears the brothers&#8217; conversation as they believe it to be private. The use of an interpreter was standard Egyptian administrative practice when dealing with Semitic speakers; it also explains how Joseph maintained his Egyptian persona — through the interpreter he speaks Egyptian, while understanding the Hebrew directly. The narrative gives the reader access to this dramatic irony: Joseph knows everything while the brothers expose their guilt assuming privacy.</p>",
"24": "<p>Joseph turns away to weep before returning. The concealment of his emotion is the emotional center of ch42: he has heard his brothers acknowledge what they did and frame it as divine punishment. He is not vindicated in the sense of being satisfied by their suffering; he is moved to tears by the recognition of the family&#8217;s guilt and pain. Then he has Simeon bound &#8220;before their eyes&#8221; — a calculated show of authority that nevertheless serves Joseph&#8217;s larger purpose. Simeon (the second oldest, associated with violence since ch34) is held rather than Reuben, the firstborn who attempted to protect Joseph.</p>",
"25": "<p>Joseph&#8217;s instructions to fill the grain sacks, return the silver, and provide journey provisions are a private act of generosity concealed within official procedure. The return of silver is the most dangerous element: discovered, it will appear as a setup (&#8220;the money was put back&#8221; suggests tampering with their transaction records). In the patron-client economy of the ANE, receiving goods without payment created a dangerous debt — the brothers cannot know whether they have been gifted or trapped. Joseph&#8217;s motivations are care for the family, but the effect creates dread.</p>",
"26": "<p>The brothers load grain and depart — apparently without incident at the border. Egyptian customs officials did exist (documents record the inspection of foreign goods at the Delta border), but the narrative does not linger on the exit. The return journey from Egypt to Canaan through the Sinai was approximately 300 km, a journey of several weeks on foot with loaded donkeys. The discovery of the silver will occur that night at a stopping point (v27), within the first day of travel.</p>",
"27": "<p>One brother discovers his silver &#8220;at the place where they stopped for the night.&#8221; The caravanserai stops along the Sinai/Negev route were known resting points; the brother opens his sack to feed his donkey and finds the money at the sack&#8217;s mouth (<em>bĕpî ʾamtaḥtô</em>). The silver is found not at the bottom of the grain but at the top — visible, undeniable. The timing — the first night of travel, before they have left the Egyptian sphere — creates maximum anxiety. If discovered by Egyptian officials, they would appear to have stolen the grain.</p>",
"28": "<p>&#8220;Their hearts sank and they turned to each other trembling.&#8221; The phrase <em>wayyēṣēʾ libbām</em> (lit. &#8220;their heart went out&#8221;) captures the physiological shock of adrenaline and fear; trembling (<em>ḥārdû</em>) is its physical expression. Their question — &#8220;What is this that God has done to us?&#8221; (<em>mah-zōʾṯ ʿāśāh ʾĕlōhîm lānû</em>) — is a second invocation of divine agency (cf. v21&#8211;22). The brothers&#8217; frame for their misfortune is consistently theological, not merely practical. They read their situation as divine punishment, not bad luck — the guilt of ch37 shapes how they interpret every subsequent crisis.</p>",
"29": "<p>The brothers&#8217; report to Jacob is detailed and careful. The narrative shifts to Canaan as Jacob hears the story for the first time. The report to Jacob sets up the family&#8217;s decision about Benjamin; everything from their journey, the official&#8217;s accusations, and the terms for Simeon&#8217;s release must be explained to the patriarch whose authority controls the next step. The reporting structure — sons returning to report to the patriarch — is a standard ANE kinship narrative pattern.</p>",
"30": "<p>The brothers&#8217; characterization of Joseph as &#8220;the man who is lord over the land&#8221; (<em>hāʾîš ʾăḏōnê hāʾāreṣ</em>) places him in the highest possible social register from a Canaanite perspective. An Egyptian official who controlled grain sales across the entire country during famine would have been experienced by foreign visitors as near-absolute power. Their description of his harsh speech establishes the contrast between his official demeanor and the concealed care the narrative shows the audience.</p>",
"31": "<p>The brothers&#8217; repeated defense of their honesty to Jacob follows the same logic they used with Joseph. In ANE kinship ethics, a man&#8217;s family was his warranty of character: &#8220;We said we were honest men, not spies&#8221; is offered as a statement of social identity backed by their collective family membership. The emphasis on honesty (<em>kēnîm</em>, from <em>kûn</em> = to be firm/established; used for reliable men of integrity) is ironic — the brothers are honest about their current mission while suppressing the defining dishonesty of their past.</p>",
"32": "<p>The brothers&#8217; report includes disclosure of their twelve-brother family structure and Joseph&#8217;s absence to Jacob. Jacob knows his family&#8217;s structure; what the narrative registers is that the brothers have disclosed to an Egyptian official (Joseph) information that Jacob would presumably prefer to keep private — the grief over the lost son, the vulnerability of the youngest. The disclosure is involuntary, extracted by Joseph&#8217;s interrogation, and it gives Joseph (and the reader) a window into how the family remembers Joseph&#8217;s disappearance: &#8220;one is no more.&#8221;</p>",
"33": "<p>The condition Joseph set — leave one brother, take grain, return with Benjamin — is reported to Jacob with its full logic: it is the only way to prove they are &#8220;honest men&#8221; rather than spies. The verification demand frames the return of Benjamin as legally required rather than optional; the brothers cannot go back to Egypt for more grain (and therefore cannot survive the famine&#8217;s second year) without satisfying Joseph&#8217;s demand. The commercial necessity of returning creates the structural pressure that will eventually drive Jacob&#8217;s decision.</p>",
"34": "<p>The promised outcome — &#8220;I will give your brother back to you, and you can trade in the land&#8221; — frames the arrangement as a commercial opportunity beyond the immediate transaction. Joseph is offering ongoing trading access if the family proves honest; this is consistent with Egyptian administrative practice of granting trusted foreign traders preferential access. The phrase &#8220;trade in the land&#8221; (<em>tisĕḥărû ʾeṯ-hāʾāreṣ</em>) suggests a longer-term economic relationship, not a one-time emergency purchase — a significant incentive beyond Simeon&#8217;s release.</p>",
"35": "<p>The discovery of all the silver pouches when the sacks are emptied at home compounds the brothers&#8217; anxiety. One discovery (v27) was terrifying; the discovery that all ten brothers&#8217; silver was returned creates a qualitatively different situation. They cannot claim the first was a mistake by a single official; the systematic return suggests either a trap or an inexplicable gift. Jacob&#8217;s fear is also evoked: &#8220;they and their father saw the money pouches, they were frightened.&#8221; Jacob now shares the brothers&#8217; sense of divine pressure (<em>wayyîrĕʾû</em>, they feared).</p>",
"36": "<p>Jacob&#8217;s lament — &#8220;You have deprived me of my children. Joseph is no more and Simeon is no more, and now you want to take Benjamin. Everything is against me!&#8221; — is one of the most emotionally raw statements in Genesis. The three losses are enumerated: Joseph (presumed dead), Simeon (held in Egypt), and the threatened loss of Benjamin. &#8220;Everything is against me&#8221; (<em>ʿālay hāyû kullānāh</em>, lit. &#8220;upon me are all these things&#8221;) is Job-like in its sense of cosmic disadvantage. The irony the audience holds is that Joseph — the first &#8220;loss&#8221; — is the very official orchestrating the situation.</p>",
"37": "<p>Reuben&#8217;s offer — &#8220;Put both of my sons to death if I do not bring him back&#8221; — is the most extreme of pledges and reveals both his genuine commitment and his political weakness as firstborn. Offering his sons as surety against Benjamin&#8217;s safety would, if literally enacted, harm Jacob&#8217;s grandchildren. Jacob recognizes that this pledge is emotionally extravagant but practically useless: killing Reuben&#8217;s sons would not restore Benjamin and would add more grief. The offer shows Reuben&#8217;s character — his instinct for dramatic gesture rather than effective action (cf. 35:22; 37:21&#8211;22; 37:29).</p>",
"38": "<p>Jacob&#8217;s refusal — &#8220;My son will not go down there with you; his brother is dead and he is the only one left&#8221; — closes the chapter with the patriarch&#8217;s veto. &#8220;The only one left&#8221; (<em>lĕbaddô nišʾar</em>, &#8220;he alone remains&#8221;) treats Benjamin as Rachel&#8217;s sole surviving son (ignoring the other sons&#8217; claims); Jacob&#8217;s favoritism has shifted completely from Joseph to Benjamin. &#8220;If harm comes to him on the journey you are taking, you will bring my gray head down to the grave in sorrow&#8221; — the phrase &#8220;gray head down to the grave&#8221; (<em>śêbātî bĕyāgôn šĕʾôlāh</em>) will recur almost verbatim in 44:31, where Judah uses it as his ultimate argument for why Benjamin must not be held. Jacob&#8217;s words become the very lever Joseph will use against the brothers in the next chapter.</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-context', 'genesis', existing)
    print(f"  ch41 verses: {len(existing.get('41', {}))}")
    print(f"  ch42 verses: {len(existing.get('42', {}))}")
    print("Genesis 41–42 mkt-context written.")

if __name__ == '__main__':
    main()
